+		`{"v":1,"agent":"kiro","cli_version":"9.9.9","type":"assistant","id":"msg-3","content":[{"type":"tool_use","id":"tu-2","name":"Write","input":{"content":"package main","path":"/repo/hello_test.go"},"result":{"output":"ok","status":"success"}}]}`,
