			Output: compactResultOutput(entry.Message.Content),
			Status: compactResultStatus(entry.Message.IsError),
		}
	}
	if err := scanner.Err(); err != nil {
		return nil, fmt.Errorf("scan tool results: %w", err)
	}
	return results, nil
}

